#include<bits/stdc++.h>
using namespace std;

int n, m, v[100001], w[100100], dp[100001], ts, cnt[1001], t[1001][1001];
bool v2[1001];

int main() {
	cin >> m >> n;
	for (int i = 1; i <= n; i++) {
		int x;
		cin >> w[i] >> v[i] >> x;
		t[x][cnt[x]++] = i;
		if (!v2[x]) {
			ts++;
			v2[x] = 1;
		}
	}
	for (int k = 1; k <= ts; k++)
		for (int i = m; i >= 0; i--)
			for (int j = 0; j < cnt[k]; j++)
				if (i >= w[t[k][j]])
					dp[i] = max(dp[i], dp[i - w[t[k][j]]] + v[t[k][j]]);
	cout << dp[m];
	return 0;
}
